SELECT v.id AS old_id, m.pk AS new_id, v.username, v.permalink,
       (EXISTS (SELECT 1 FROM "VisibleMention" x WHERE x.id = m.pk)) AS target_exists
FROM "VisibleMention" v
JOIN _sc_pk m
  ON substring(v.permalink from 'instagram\.com/(?:p|reel|tv)/([^/?#]+)') = m.code
WHERE v.id <> m.pk
ORDER BY target_exists DESC, v.username;

-- ============================================================================
-- 第 2 步：执行（含事务，出错自动回滚）。确认第 1 步无误后整段运行。
--   · 无冲突的行：把 id 改成新 pk
--   · 冲突的行（new_id 已存在 = 之前已用新代码重新筛过）：删掉旧 id 那条
--   · 想顺便清空 Mention 缓存让下次 sync 重建，取消最后一行 DELETE 的注释
-- ============================================================================
BEGIN;

CREATE TEMP TABLE _sc_pk (code text PRIMARY KEY, pk text NOT NULL) ON COMMIT DROP;

