-- 1) 无冲突：改 id
UPDATE "VisibleMention" v
SET id = m.pk
FROM _sc_pk m
WHERE substring(v.permalink from 'instagram\.com/(?:p|reel|tv)/([^/?#]+)') = m.code
  AND v.id <> m.pk
  AND NOT EXISTS (SELECT 1 FROM "VisibleMention" x WHERE x.id = m.pk);

-- 2) 冲突：删旧
DELETE FROM "VisibleMention" v
USING _sc_pk m
WHERE substring(v.permalink from 'instagram\.com/(?:p|reel|tv)/([^/?#]+)') = m.code
  AND v.id <> m.pk
  AND EXISTS (SELECT 1 FROM "VisibleMention" x WHERE x.id = m.pk);

